</head>
<body>
    <h1>Buggy Version (Memory Leak)</h1>
    <button id="add-buggy-widget">Add Buggy Widget</button>
    <button id="remove-buggy-widget">Remove Buggy Widget</button>
    <div id="buggy-widgets"></div>
    <p>Buggy Widget Count: <span id="buggy-widget-count">0</span></p>

