        // Buggy Version
        let buggyWidgetCount = 0;
        const buggyWidgets = [];

        document.getElementById('add-buggy-widget').addEventListener('click', () => {
            const widget = document.createElement('div');
            widget.className = 'widget';
            widget.innerHTML = `Buggy Widget ${buggyWidgetCount}`;
            document.getElementById('buggy-widgets').appendChild(widget);

            // Attach event listener and store DOM reference
            widget.addEventListener('click', () => {
                console.log(`Buggy Widget ${buggyWidgetCount} clicked`);
