            buggyWidgetCount++;
            document.getElementById('buggy-widget-count').textContent = buggyWidgetCount;
        });

        document.getElementById('remove-buggy-widget').addEventListener('click', () => {
            if (buggyWidgets.length > 0) {
                const widget = buggyWidgets.pop();
                widget.parentNode.removeChild(widget);
                buggyWidgetCount--;
                document.getElementById('buggy-widget-count').textContent = buggyWidgetCount;
            }
        });

        // Fixed Version
        let fixedWidgetCount = 0;
        const fixedWidgets = [];

        document.getElementById('add-fixed-widget').addEventListener('click', () => {
            const widget = document.createElement('div');
            widget.className = 'widget';
            widget.innerHTML = `Fixed Widget ${fixedWidgetCount}`;
            document.getElementById('fixed-widgets').appendChild(widget);

            // Attach event listener with a wrapper function
            const handleClick = () => {
                console.log(`Fixed Widget ${fixedWidgetCount} clicked`);
            };
            widget.addEventListener('click', handleClick);

            fixedWidgets.push({ widget, handleClick });
            fixedWidgetCount++;
            document.getElementById('fixed-widget-count').textContent = fixedWidgetCount;
        });

        document.getElementById('remove-fixed-widget').addEventListener('click', () => {
            if (fixedWidgets.length > 0) {
                const { widget, handleClick } = fixedWidgets.pop();
                widget.removeEventListener('click', handleClick);
